// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check title screen name', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check title screen name', async function() {
    await driver.get("http://localhost:4200/user/evaluation-description");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.css(".ant-layout-content > .ant-typography")).click();
    await driver.findElement(By.css(".ant-layout-content > .ant-typography")).click();
    await driver.findElement(By.css(".ant-layout-content > .ant-typography")).click();
    {
      const element = await driver.findElement(By.css(".ant-layout-content > .ant-typography"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }
    await driver.findElement(By.css(".ant-layout-content > .ant-typography")).click();
    assert(await driver.findElement(By.css(".ant-layout-content > .ant-typography")).getText() == "評価基準案内");
  });
});
